			if ok {
				dispatch.Assigns[aIdx].GenRoute()
				newCost := dispatch.Assigns[aIdx].Cost
				if newCost >= 0 {
					incr := newCost - origCost
					if incr < 0 {
						incr = 0
					}

					compactBenefit := 0.0
					if aIdx < dispatch.AssignsLen && dispatch.Assigns[aIdx].StationCurrent.X != 0 || dispatch.Assigns[aIdx].StationCurrent.Y != 0 {
						distToOri := cal_dis(dispatch.Assigns[aIdx].StationCurrent, oriSt)
						compactBenefit = 1.0 / (1.0 + distToOri)
					}

					timeSlack := 0.0
					if oriSt.TimeStart >= 0 && desSt.TimeEnd >= 0 {
						windowWidth := float64(desSt.TimeEnd - oriSt.TimeStart)
						if windowWidth > 0 {
							timeSlack = 1.0 / (1.0 + windowWidth)
						}
					}

					compositeScore := alphaDist*incr - betaCompact*compactBenefit - gammaTime*timeSlack

					candidates = append(candidates, candInfo{
						assignIdx:     aIdx,
						score:         compositeScore,
